function initiateAccountRecoveryDisablement(
  address smartWallet, uint256 extraTime
) external onlyOwnerOr(Role.OPERATOR) {
  require(smartWallet != address(0), "No smart wallet address provided.");

  // Set the timelock and emit a `TimelockInitiated` event.
  _setTimelock(
    this.disableAccountRecovery.selector, abi.encode(smartWallet), extraTime
  );
}

function disableAccountRecovery(
  address smartWallet
) external onlyOwnerOr(Role.DISABLER) {
  require(smartWallet != address(0), "No smart wallet address provided.");

  // Ensure that the timelock has been set and is completed.
  _enforceTimelock(abi.encode(smartWallet));

  // Register the specified wallet as having opted out of account recovery.
  _accountRecoveryDisabled[smartWallet] = true;

  // Emit an event to signify the wallet in question is no longer recoverable.
  emit RecoveryDisabled(smartWallet);
}

function cancelAccountRecoveryDisablement(
  address smartWallet
) external onlyOwnerOr(Role.CANCELLER) {
  require(smartWallet != address(0), "No smart wallet address provided.");

  // Expire account recovery disablement timelock in question if one exists.
  _expireTimelock(
    this.disableAccountRecovery.selector, abi.encode(smartWallet)
  );

  // Emit an event to signify that the recovery disablement was cancelled.
  emit RecoveryDisablementCancelled(smartWallet);
}

function unpause(Role role) external onlyOwner {
  RoleStatus storage storedRoleStatus = _roles[uint256(role)];
  require(storedRoleStatus.paused, "Role in question is already unpaused.");
  storedRoleStatus.paused = false;
  emit RoleUnpaused(role);
}

function modifyTimelockInterval(
  bytes4 functionSelector, uint256 newTimelockInterval
) external onlyOwner {
  // Ensure that a function selector is specified (no 0x00000000 selector).
  require(
    functionSelector != bytes4(0),
    "Function selector cannot be empty."
  );

  // Continue via logic in the inherited `_modifyTimelockInterval` function.
  _modifyTimelockInterval(functionSelector, newTimelockInterval);
}

function newKeyRingAndAdditionalKey(
  address userSigningKey,
  address additionalSigningKey,
  bytes calldata signature
) external returns (address keyRing) {
  // Deploy and initialize a keyring instance and emit a corresponding event.
  keyRing = _deployNewKeyRing(userSigningKey);

  // Set the additional key on the newly-deployed keyring.
  DharmaKeyRingImplementationV0Interface(keyRing).takeAdminAction(
    DharmaKeyRingImplementationV0Interface.AdminActionType.AddDualKey,
    uint160(additionalSigningKey),
    signature
  );
}

function permit(address owner, PermitSingle memory permitSingle, bytes calldata signature) external {
    if (block.timestamp > permitSingle.sigDeadline) revert SignatureExpired(permitSingle.sigDeadline);

    // Verify the signer address from the signature.
    signature.verify(_hashTypedData(permitSingle.hash()), owner);

    _updateApproval(permitSingle.details, owner, permitSingle.spender);
}

function _updateApproval(PermitDetails memory details, address owner, address spender) private {
    uint48 nonce = details.nonce;
    address token = details.token;
    uint160 amount = details.amount;
    uint48 expiration = details.expiration;
    PackedAllowance storage allowed = allowance[owner][token][spender];

    if (allowed.nonce != nonce) revert InvalidNonce();

    allowed.updateAll(amount, expiration, nonce);
    emit Permit(owner, token, spender, amount, expiration, nonce);
}

function permitWitnessTransferFrom(
        PermitTransferFrom memory permit,
        SignatureTransferDetails calldata transferDetails,
        address owner,
        bytes32 witness,
        string calldata witnessTypeString,
        bytes calldata signature
    ) external;

function permitWitnessTransferFrom(
        PermitBatchTransferFrom memory permit,
        SignatureTransferDetails[] calldata transferDetails,
        address owner,
        bytes32 witness,
        string calldata witnessTypeString,
        bytes calldata signature
    ) external;

function updateAmountAndExpiration(
    IAllowanceTransfer.PackedAllowance storage allowed,
    uint160 amount,
    uint48 expiration
) internal {
    // If the inputted expiration is 0, the allowance only lasts the duration of the block.
    allowed.expiration = expiration == 0 ? uint48(block.timestamp) : expiration;
    allowed.amount = amount;
}

function permitTransferFrom(
    PermitTransferFrom memory permit,
    SignatureTransferDetails calldata transferDetails,
    address owner,
    bytes calldata signature
) external {
    _permitTransferFrom(permit, transferDetails, owner, permit.hash(), signature);
}

function _erc1271IsValidSignatureNowCalldata(bytes32 hash, bytes calldata signature)
        internal
        view
        virtual
        returns (bool)
    {
        return SignatureCheckerLib.isValidSignatureNowCalldata(_erc1271Signer(), hash, signature);
    }

function _erc1271IsValidSignatureViaSafeCaller(bytes32 hash, bytes calldata signature)
        internal
        view
        virtual
        returns (bool result)
    {
        if (_erc1271CallerIsSafe()) {
            result = _erc1271IsValidSignatureNowCalldata(hash, signature);
        }
    }

function validateUserOp(
    PackedUserOperation calldata userOp,
    bytes32 userOpHash,
    uint256 missingAccountFunds
)
    external
    payable
    virtual
    onlyEntryPoint
    payPrefund(missingAccountFunds)
    returns (uint256 validationData)
{
    validationData = _validateSignature(userOp, userOpHash);
    _validateNonce(userOp.nonce);
}

function _isValidSigner(address signer, bytes32 extraData, bytes calldata context)
        internal
        view
        virtual
        returns (bool)
    {
        extraData = extraData; // Silence unused variable warning.
        context = context; // Silence unused variable warning.
        return signer == owner();
    }

function setTimedRole(address holder, uint256 timedRole, uint40 start, uint40 expires)
        public
        payable
        virtual
    {
        _authorizeSetTimedRole(holder, timedRole, start, expires);
        _setTimedRole(holder, timedRole, start, expires);
    }
